import{_ as e,o as a,c as i,a as n}from"./chunks/framework.8tiMeCK-.js";const k=JSON.parse('{"title":"9.7  实战：使用 set_event 接口跟踪单次 Ping 请求","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch09_7.md","filePath":"notes/linux_kernel_debugging/ch09_7.md","lastUpdated":null}'),t={name:"notes/linux_kernel_debugging/ch09_7.md"};function p(l,s,r,c,o,d){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="_9-7-实战-使用-set-event-接口跟踪单次-ping-请求" tabindex="-1">9.7 实战：使用 set_event 接口跟踪单次 Ping 请求 <a class="header-anchor" href="#_9-7-实战-使用-set-event-接口跟踪单次-ping-请求" aria-label="Permalink to &quot;9.7  实战：使用 set_event 接口跟踪单次 Ping 请求&quot;">​</a></h1><p>上一节我们用 <code>available_filter_functions</code> 这种「大撒网」的方式，把整个网络栈的函数调用图给扒了出来。虽然直观，但这就好比为了听清楚两个人在说什么，你把整栋楼人的麦克风都打开了——噪音太大，信息量太溢出。</p><p>其实，ftrace 还有另一种视角。它不是盯着「函数」看，而是盯着「事件」看。</p><p>这不仅仅是换个接口的问题——这两种方式看到的内核，是完全不同的两个切面。</p><h3 id="从函数到事件" tabindex="-1">从函数到事件 <a class="header-anchor" href="#从函数到事件" aria-label="Permalink to &quot;从函数到事件&quot;">​</a></h3><p>回想一下上一节的流程：我们把函数名写进 <code>set_ftrace_filter</code>，告诉 ftrace 「盯着这几个函数」。这很直觉，但有个问题：你得先知道函数名。</p><p>对于那些内核里已经定义好的「关键节点」，为什么还要我们自己去猜函数名呢？内核开发者早就帮我们把标记插好了。这些标记，就是 <strong>Tracepoints（跟踪点）</strong>。</p><blockquote><p><strong>你可以把 Tracepoints 想象成埋在高速公路上的感应线圈。</strong> 上一种方法（<code>available_filter_functions</code>）就像是在路边派每个人去盯每一辆车；而 <code>set_event</code> 则是直接读取感应线圈的记录。</p><p>但这个类比有个地方需要小心：感应线圈只能告诉你「车经过了」，上下文不如盯梢的人丰富。在 ftrace 里，这意味着你会看到具体的<strong>参数值</strong>，但可能会失去<strong>函数调用的缩进层级</strong>。</p></blockquote><p>所有这些事件，都整齐地排列在 <code>/sys/kernel/tracing/events</code> 目录下。</p><p>看看这张图（图 9.16），这就是内核的「事件超市」：</p><p><em>图 9.16 – <code>/sys/kernel/tracing/events</code> 目录内容——所有内核跟踪点</em></p><p>还记得我们在第 4 章（《Debug via Instrumentation – Kprobes》）里聊过的动态 kprobes 吗？其实我们在那里已经用过这个事件追踪框架了。当时是用它来追踪那些没有内置跟踪点的函数，而现在，我们是在用内核自带的「原装」追踪点。</p><h3 id="精简追踪范围——只看网络" tabindex="-1">精简追踪范围——只看网络 <a class="header-anchor" href="#精简追踪范围——只看网络" aria-label="Permalink to &quot;精简追踪范围——只看网络&quot;">​</a></h3><p>如果我们只关心网络，那么 <code>events</code> 目录下的 <code>net</code>、<code>sock</code>、<code>skb</code>、<code>tcp</code>、<code>udp</code> 这些子目录就是我们的目标。</p><p>使用 <code>set_event</code> 接口的语法非常简单：直接把「系统:事件」的字符串 echo 进去就行了。如果你想一次性开启某个子系统下的所有事件，通配符 <code>*</code> 就派上用场了。</p><p>这比上一节的脚本要清爽得多。我们只需要把 <code>FILTER_VIA_AVAIL_FUNCS</code> 设为 0，脚本就会走另一条分支：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ch9/ftrace/ping_ftrace.sh</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FILTER_VIA_AVAIL_FUNCS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;[+] Function filtering:&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ \${FILTER_VIA_AVAIL_FUNCS} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-eq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ] ; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   [... 上一节的逻辑 ...] </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 通过 set_event 接口进行过滤</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 这种方法很快，但细节会少一些！</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 我们会失去函数图的缩进，但能看到函数参数！</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot; Alternate event-based filtering (via set_event):&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;net:* sock:* skb:* tcp:* udp:* napi:* qdisc:* neigh:* syscalls:*&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set_event</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>注意这里我加了一句 <code>syscalls:*</code>。为什么要看系统调用？因为我们需要上下文。只看网络包的来龙去脉，不知道是谁发的，就像看一场没有主角的电影。</p><h3 id="输出结果——有得必有失" tabindex="-1">输出结果——有得必有失 <a class="header-anchor" href="#输出结果——有得必有失" aria-label="Permalink to &quot;输出结果——有得必有失&quot;">​</a></h3><p>跑一下这个脚本，然后再发起一次 Ping。这一次，<code>trace</code> 文件里的内容画风大变。</p><p>这是部分输出（图 9.17）：</p><p><em>图 9.17 – 通过 set_event 接口获取的 ftrace 报告（已过滤）</em></p><p>看出来了吗？</p><p><strong>我们失去了一些东西，也得到了一些东西。</strong></p><p>❌ <strong>失去的</strong>：那个漂亮的、像代码缩进一样的函数调用层级图不见了。这就像把调用栈拍扁了，你很难一眼看出 <code>udp_sendmsg</code> 是不是嵌套在 <code>ip_send_fill_frag</code> 里面。</p><p>✅ <strong>得到的</strong>：每一行后面多了详细的东西——<strong>函数参数的值</strong>。这太关键了。对于调试来说，知道「调用了这个函数」只是第一步，知道「传入的缓冲区指针是多少」才是定纷止争的关键。</p><p>如果是用 <code>trace-cmd</code> 工具（下一节马上讲），当你不使用 <code>function_graph</code> 插件时，它默认就会把参数打印出来，这和现在的行为是一致的。</p><blockquote><p><strong>回到那个「高速公路感应线圈」的类比：</strong> 现在输出的报告里，每一个参数值就像是感应线圈抓拍的照片。你可能没看到车是怎么开进来的（失去了层级缩进），但你可以清晰地看到车牌号和载重（得到了参数值）。对于排查「为什么参数错了导致丢包」这类问题，这种视角往往比看几千行缩进图更管用。</p></blockquote><h3 id="快速插入调试点——trace-printk" tabindex="-1">快速插入调试点——trace_printk() <a class="header-anchor" href="#快速插入调试点——trace-printk" aria-label="Permalink to &quot;快速插入调试点——trace_printk()&quot;">​</a></h3><p>说到调试参数，这里插播一个极其好用的 API：<code>trace_printk()</code>。</p><p>很多内核新手喜欢用 <code>printk()</code> 打日志，跑起来才发现：「卧槽，日志刷得太慢了，把系统时序都打乱了」，或者更惨的，「<code>printk()</code> 缓冲区溢出了，关键信息丢了」。</p><p><code>trace_printk()</code> 就是为了解决这个痛点存在的。它的语法和 <code>printf()</code> 一模一样：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">trace_printk</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;myprj: at </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">%s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">%s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">():</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">%d\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">__FILE__</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, __func__, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">__LINE__</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>它和 printk 的本质区别在于</strong>：</p><ol><li><strong>速度</strong>：它只写内存（ftrace 的 ring buffer），绝不碰控制台设备。这在处理中断这种「快如闪电」的代码路径时至关重要，否则就会出现海森堡 Bug——你看它，它就变样。</li><li><strong>容量</strong>：ftrace 的缓冲区通常比 printk 的日志缓冲区大得多，而且是可调的。</li><li><strong>读取方式</strong>：你在 <code>dmesg</code> 里是看不到它的。必须去读 <code>/sys/kernel/tracing/trace</code> 或 <code>trace_pipe</code>。</li></ol><p>还有一个小技巧：如果你用 <code>function_graph</code> 跟踪器，<code>trace_printk()</code> 的输出会显示为注释（<code>/* ... */</code>），混在函数调用流里，非常方便定位是哪一步打印的。</p><p>⚠️ <strong>注意</strong> 内核文档明确说了，这东西仅供调试使用。不要把它留在正式代码里。</p><p>如果你只需要打印一个固定的字符串（不需要格式化），用 <code>trace_puts()</code> 会更快。内核开发者连这都想到了。</p><p>如果你想关掉这个功能（不想让 <code>trace_printk</code> 污染你的 trace），可以在 <code>trace_options</code> 里把 <code>notrace_printk</code> 写进去，或者往 <code>options/trace_printk</code> 里写 <code>0</code>。</p>`,39)])])}const g=e(t,[["render",p]]);export{k as __pageData,g as default};
